import React, { useEffect, useState, useContext } from 'react';
import { Link, useSearchParams, useParams } from 'react-router-dom';
import api from '../api';
import { CartContext } from '../context/CartContext';
import { CreditCard, ArrowLeft } from 'lucide-react';
import { getProductUrl } from '../utils/urls';
import shopConfig from '../shop.config';
import { useCategories } from '../context/CategoryContext';

export default function Catalog({ predefinedCategory, predefinedSlug }) {
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const { addToCart } = useContext(CartContext);
    const { categorySlug } = useParams();
    const [searchParams] = useSearchParams();
    const { categories } = useCategories();

    // Determine category to filter
    const categoryQuery = searchParams.get('category');
    const activeCategorySlug = predefinedCategory || categorySlug || categoryQuery;
    const activeCategory = categories.find(c => c.slug === activeCategorySlug);

    useEffect(() => {
        setLoading(true);
        window.scrollTo(0, 0); // Reset scroll on load
        api.get('/products/', { params: { category: activeCategorySlug } })
            .then(response => {
                setProducts(response.data);
                setLoading(false);
            })
            .catch(error => {
                console.error("Error fetching products:", error);
                setLoading(false);
            });
    }, [activeCategorySlug]);

    // Handle Quick Order simulation (or actual add to cart + modal)
    const handleQuickOrder = (product) => {
        addToCart(product, 1, null, null, null, 'pickup');
        // If we had a quick order modal, we'd open it here. 
        // For now, we just redirect or alert/add to cart.
        alert(`Товар "${product.name}" додано до кошика! Обробка швидкого замовлення...`);
    };

    const getPageTitle = () => {
        if (activeCategory) return activeCategory.name;
        return 'Всі товари';
    };

    return (
        <div className="min-h-screen bg-gray-50 pb-20">
            {/* Header / Breadcrumbs */}
            <div className="bg-white border-b border-gray-200 py-8 px-4 sm:px-8 xl:px-16">
                <div className="max-w-7xl mx-auto flex flex-col items-start gap-4">
                    <Link to="/" className="text-gray-500 hover:text-orange-500 flex items-center gap-2 text-sm font-medium transition-colors">
                        <ArrowLeft size={16} /> На головну
                    </Link>
                    <h1 className="text-3xl md:text-5xl font-black text-gray-900 tracking-tight uppercase">
                        {getPageTitle()}
                    </h1>
                </div>
            </div>

            {/* Catalog Grid */}
            <div className="max-w-7xl mx-auto px-4 sm:px-8 xl:px-16 py-12">
                {loading ? (
                    <div className="flex justify-center items-center py-20">
                        <div className="w-12 h-12 border-4 border-orange-200 border-t-orange-500 rounded-full animate-spin"></div>
                    </div>
                ) : products.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-2xl shadow-sm border border-gray-100">
                        <p className="text-gray-500 text-lg">У цій категорії поки немає товарів.</p>
                        <Link to="/catalog/" className="text-orange-500 font-bold hover:underline mt-4 inline-block">
                            Показати всі товари
                        </Link>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
                        {products.map((product) => (
                            <div
                                key={product.id}
                                className="bg-white rounded-[2rem] overflow-hidden shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 hover:shadow-[0_20px_50px_rgba(249,115,22,0.15)] transition-all duration-500 group flex flex-col relative"
                            >
                                {/* В наявності Badge */}
                                <div className="absolute top-4 left-4 z-10 bg-green-500 text-white text-[10px] sm:text-xs font-bold px-2 py-1 rounded-sm uppercase tracking-wider shadow-sm">
                                    В наявності
                                </div>

                                <Link to={getProductUrl(product)} className="block h-72 sm:h-80 overflow-hidden relative bg-gray-50">
                                    {product.image_url ? (
                                        <img
                                            src={product.image_url.startsWith('http') ? product.image_url : `${api.defaults.baseURL}${product.image_url}`}
                                            alt={product.name}
                                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 ease-in-out"
                                            style={{ imageRendering: 'high-quality' }}
                                        />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-gray-400">
                                            <span>Немає фото</span>
                                        </div>
                                    )}
                                    <div className="absolute inset-0 bg-black/5 group-hover:bg-transparent transition-colors duration-300"></div>
                                </Link>

                                <div className="p-5 sm:p-6 text-left flex flex-col flex-grow">
                                    <Link to={getProductUrl(product)} className="hover:text-orange-500 transition-colors">
                                        <h3 className="text-gray-900 mb-2 text-lg sm:text-xl font-extrabold leading-tight">
                                            {product.name}
                                        </h3>
                                    </Link>

                                    <p className="text-gray-500 text-xs sm:text-sm font-medium mb-4 flex-grow line-clamp-2">
                                        {product.description || 'Щільно укладені дрова, готові до використання. Розмір полін 35-40 см.'}
                                    </p>

                                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mt-auto pt-4 border-t border-gray-100">
                                        <div className="flex flex-col">
                                            <span className="text-[10px] text-gray-400 uppercase tracking-wider font-bold mb-0.5">Ціна за склм</span>
                                            <div className="flex items-center gap-2">
                                                {product.price > 1000 && (
                                                    <span className="text-gray-400 line-through text-xs sm:text-sm font-bold">
                                                        {Math.round(product.price * 1.15)} грн
                                                    </span>
                                                )}
                                                <p className="text-orange-600 font-extrabold text-xl sm:text-2xl leading-none">
                                                    {product.price} <span className="text-sm">грн</span>
                                                </p>
                                            </div>
                                        </div>
                                        <button
                                            onClick={(e) => { e.preventDefault(); handleQuickOrder(product); }}
                                            className="bg-orange-500 hover:bg-orange-600 active:scale-95 text-white px-5 h-11 sm:h-12 rounded-lg flex items-center justify-center gap-2 transition-all shadow-md font-bold text-sm w-full sm:w-auto"
                                        >
                                            <CreditCard size={18} /> Купити
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* SEO Text Section if Category has it */}
            {activeCategory && activeCategory.seo_text && (
                <div className="max-w-7xl mx-auto px-4 sm:px-8 xl:px-16 py-12">
                    <div className="bg-white rounded-[2rem] p-8 md:p-12 shadow-sm border border-gray-100 prose prose-orange max-w-none prose-headings:font-bold prose-headings:tracking-tight hover:shadow-md transition-shadow">
                        <div dangerouslySetInnerHTML={{ __html: activeCategory.seo_text }} />
                    </div>
                </div>
            )}
        </div>
    );
}
